import { zodResolver } from '@hookform/resolvers/zod';import { useForm } from 'react-hook-form';import { Button } from '@/components/ui/button';import { ratingSchema } from '../schemas';import type { RatingFormValues } from '../types';const cls='mt-1 h-10 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800';
export const RatingForm=({currency,onSubmit,onCancel,isLoading}:{currency:string;onSubmit:(v:RatingFormValues)=>void;onCancel:()=>void;isLoading?:boolean})=>{const end=new Date().toISOString().slice(0,10);const start=`${end.slice(0,4)}-01-01`;const {register,handleSubmit,formState:{errors}}=useForm<RatingFormValues>({resolver:zodResolver(ratingSchema),mode:'onTouched',defaultValues:{review_period_start:start,review_period_end:end,product_quality_score:5,currency,notes:''}});return <form onSubmit={handleSubmit(onSubmit)} className="space-y-4"><div className="grid gap-4 sm:grid-cols-2"><label className="text-sm font-semibold">Review Period Start<input type="date" {...register('review_period_start')} className={cls}/></label><label className="text-sm font-semibold">Review Period End<input type="date" {...register('review_period_end')} className={cls}/></label><label className="text-sm font-semibold">Product Quality (0–5)<input type="number" min={0} max={5} step="0.1" {...register('product_quality_score')} className={cls}/></label><label className="text-sm font-semibold">Currency<input {...register('currency')} className={cls}/></label></div>{errors.review_period_end?<p className="text-xs text-red-600">{errors.review_period_end.message}</p>:null}<p className="rounded-lg bg-slate-50 p-3 text-xs text-slate-500 dark:bg-slate-800">Delivery, completion, returns, lead time, and procurement value are calculated from Purchasing records for this review period.</p><label className="block text-sm font-semibold">Review Notes<textarea {...register('notes')} rows={3} className={`${cls} h-auto py-2`}/></label><div className="flex justify-end gap-2"><Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button><Button type="submit" isLoading={isLoading}>Create Performance Review</Button></div></form>;};
